// \u2500\u2500 CRUD \u2500\u2500
async function savePlayer() {
  const nome = document.getElementById('f-nome').value.trim()
  if (!nome) { showToast('O nome \u00e9 obrigat\u00f3rio', 'error'); return }
  const btn = document.getElementById('form-save')
  btn.disabled = true
  btn.textContent = 'A guardar...'

  // Handle local file upload
  const fileInput = document.getElementById('f-foto-file')
  let fotoUrl = document.getElementById('f-foto').value.trim() || null
  if (fileInput && fileInput.files && fileInput.files[0]) {
    const file = fileInput.files[0]
    fotoUrl = await new Promise((resolve) => {
      const reader = new FileReader()
      reader.onload = e => resolve(e.target.result)
      reader.readAsDataURL(file)
    })
  }

  const ig = document.getElementById('f-instagram').value.trim().replace(/^@/, '')
  const igLink = ig ? `https://www.instagram.com/${ig}/` : null
  const data = {
    nome,
    posicao: document.getElementById('f-posicao').value || null,
    nivel: document.getElementById('f-nivel-form').value || null,
    clube: document.getElementById('f-clube').value.trim() || null,
    ano: parseInt(document.getElementById('f-ano-form').value) || null,
    representante: document.getElementById('f-representante').value.trim() || null,
    referenciador: document.getElementById('f-referenciador').value.trim() || null,
    telefone: document.getElementById('f-telefone').value.trim() || null,
    instagram: ig || null,
    instagram_link: igLink,
    foto: fotoUrl,
    link: document.getElementById('f-link').value.trim() || null,
    video: document.getElementById('f-video').value.trim() || null,
    notas: document.getElementById('f-notas').value.trim() || null,
  }
  let error
  // Determine correct table - use player's original table if in geral
  let activeTable
  if (state.editingPlayer && state.editingPlayer._sourceTable) {
    activeTable = state.editingPlayer._sourceTable
  } else {
    activeTable = DATABASES.find(d => d.id === state.activeDb)?.table || 'players'
  }
  // Remove null values to avoid column-not-found errors on different tables
  const cleanData = Object.fromEntries(Object.entries(data).filter(([_, v]) => v !== null && v !== undefined && v !== ''))
  let result
  if (state.editingPlayer) {
    result = await supabase.from(activeTable).update(cleanData).eq('id', state.editingPlayer.id)
  } else {
    cleanData.data_insercao = new Date().toISOString().split('T')[0]
    result = await supabase.from(activeTable).insert(cleanData)
  }
  error = result.error
  if (error) {
    showToast('Erro: ' + error.message, 'error')
    btn.disabled = false
    btn.textContent = state.editingPlayer ? 'Guardar' : 'Adicionar jogador'
    return
  }
  const isNew = !state.editingPlayer
  showToast(isNew ? 'Jogador adicionado!' : 'Jogador atualizado!', 'success')
  if (isNew) {
    sendLocalNotification('Novo jogador adicionado!', `${nome} foi adicionado \u00e0 base de dados.`)
  }
  // Clear ALL cache and force fresh reload
  Object.keys(state.dbCache).forEach(k => { state.dbCache[k] = null })
  closeAll()
  await loadPlayers()
}

async function deletePlayer(player) {
  if (!confirm(`Tens a certeza que queres eliminar "${player.nome}"?`)) return
  const { error } = await supabase.from(player._sourceTable || DATABASES.find(d => d.id === state.activeDb)?.table || 'players').delete().eq('id', player.id)
  if (error) { showToast('Erro ao eliminar.', 'error'); return }
  showToast('Jogador eliminado.', 'success')
  closeAll()
  // Clear cache so fresh data is loaded
  state.dbCache[state.activeDb] = null
  state.dbCache['geral'] = null
  await loadPlayers()
}


// Preload all tabs in background
async function preloadAll() {
  // Load all tables in parallel
  const tables = DATABASES.filter(db => !db.isGeral && db.table)
  const results = await Promise.all(tables.map(db => supabase.from(db.table).select('*')))
  tables.forEach((db, i) => {
    const { data } = results[i]
    if (data) state.dbCache[db.id] = data.map(p => ({ ...p, ano: p.ano != null ? String(p.ano) : '' }))
  })
  // Build geral from cache
  const all = [
    ...(state.dbCache['mercado'] || []).map(p => ({...p, _source: 'Mercado', _sourceTable: 'players_mercado'})),
    ...(state.dbCache['cbf'] || []).map(p => ({...p, _source: 'CBF Sele\u00e7\u00f5es', _sourceTable: 'players'})),
    ...(state.dbCache['fpf'] || []).map(p => ({...p, _source: 'FPF Sele\u00e7\u00f5es', _sourceTable: 'players_portugal'})),
    ...(state.dbCache['ligas-portugal'] || []).map(p => ({...p, _source: 'Liga Portugal', _sourceTable: 'players_ligas_portugal'})),
    ...(state.dbCache['ligas-brasil'] || []).map(p => ({...p, _source: 'Brasileir\u00e3o', _sourceTable: 'players_ligas_brasil'})),
  ].sort((a,b) => (a.nome||'').localeCompare(b.nome||''))
  state.dbCache['geral'] = all
}
async function loadPedidos() {
  const { data, error } = await supabase.from('club_requests').select('*')
  if (error) { showToast('Erro ao carregar pedidos.', 'error'); return }
  state.pedidos = data || []
  state.pedidoSortCol = state.pedidoSortCol || 'clube'
  state.pedidoSortDir = state.pedidoSortDir || 1
  state.pedidoSearch = state.pedidoSearch || ''
  applyPedidoFilters()
}

function updatePedidoSortUI() {
  const col = state.pedidoSortCol || 'clube'
  const dir = state.pedidoSortDir || 1
  document.querySelectorAll('.pedido-sort-btn').forEach(btn => {
    const arrow = btn.querySelector('.psb-arrow')
    if (btn.dataset.col === col) {
      btn.classList.add('active')
      if (arrow) arrow.textContent = dir === 1 ? '\u2191' : '\u2193'
    } else {
      btn.classList.remove('active')
      if (arrow) arrow.textContent = '\u2195'
    }
  })
}

function renderPedidos() {
  const container = document.getElementById('player-list')
  if (!container) return

  const stats = document.getElementById('stats-count')
  const pedidos = state.pedidosFiltered || state.pedidos || []
  const total = state.pedidos?.length || 0
  if (stats) stats.innerHTML = `<strong>${pedidos.length}</strong> de ${total} Pedidos`

  const sortSel = document.getElementById('pedido-sort-col')
  if (sortSel) sortSel.value = state.pedidoSortCol || 'clube'
  const sortDir = document.getElementById('pedido-sort-dir')
  if (sortDir) sortDir.textContent = (state.pedidoSortDir || 1) === 1 ? '\u2191\u2193' : '\u2193\u2191'

  updatePedidoSortUI()

  if (!pedidos.length) {
    container.innerHTML = '<div class="empty-state"><div class="empty-icon">\ud83d\udccb</div><div>Sem pedidos de clubes</div></div>'
    return
  }

  container.innerHTML = pedidos.map(p => {
    const initClube = (p.clube || '?').substring(0, 2).toUpperCase()
    const logoHtml = p.logo_url
      ? `<img class="pedido-logo" src="${p.logo_url}" alt="${p.clube}" />`
      : `<div class="pedido-initials">${initClube}</div>`
    return `
      <div class="player-row pedido-row" data-id="${p.id}">
        <div class="player-info">
          ${logoHtml}
          <div class="pedido-text">
            <div class="player-name">${p.clube || '\u2014'}</div>
            <div class="player-meta">${p.pais || '\u2014'}</div>
          </div>
        </div>
        <div class="pedido-cols">
          <div class="pedido-col-item">
            ${p.posicao ? `<span class="pos-badge">${p.posicao}</span>` : '<span class="pedido-col-empty">\u2014</span>'}
          </div>
          <div class="pedido-col-item">
            <span class="pedido-col-val">${p.valor_transferencia || '\u2014'}</span>
          </div>
          <div class="pedido-col-item">
            <span class="pedido-col-val">${p.salario || '\u2014'}</span>
          </div>
          <div class="pedido-col-item">
            <span class="pedido-col-val pedido-col-budget">${p.budget_total || '\u2014'}</span>
          </div>
        </div>
        <svg class="row-chevron" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><polyline points="9 18 15 12 9 6"/></svg>
      </div>
    `
  }).join('')

  container.querySelectorAll('.pedido-row').forEach(row => {
    row.addEventListener('click', () => {
      const pedido = (state.pedidosFiltered || state.pedidos || []).find(p => String(p.id) === String(row.dataset.id))
      if (pedido) openPedidoPanel(pedido)
    })
  })
}
function applyPedidoFilters() {
  let list = [...(state.pedidos || [])]
  if (state.pedidoSearch) {
    const q = state.pedidoSearch.toLowerCase()
    list = list.filter(p => (p.clube||'').toLowerCase().includes(q) || (p.pais||'').toLowerCase().includes(q))
  }
  if (state.pedidoFilterPos) list = list.filter(p => p.posicao === state.pedidoFilterPos)
  if (state.pedidoFilterClube) list = list.filter(p => p.clube === state.pedidoFilterClube)
  if (state.pedidoFilterPais) list = list.filter(p => p.pais === state.pedidoFilterPais)
  const col = state.pedidoSortCol || 'clube'
  const dir = state.pedidoSortDir || 1
  list.sort((a, b) => dir * (a[col]||'').toString().localeCompare((b[col]||'').toString()))
  state.pedidosFiltered = list
  populatePedidoFilterDropdowns()
  renderPedidos()
}

async function openPedidoPanel(pedido) {
  const allPlayers = [
    ...(state.dbCache['cbf'] || []),
    ...(state.dbCache['mercado'] || []),
    ...(state.dbCache['fpf'] || []),
    ...(state.dbCache['ligas-portugal'] || []),
    ...(state.dbCache['ligas-brasil'] || []),
  ]

  let currentSuggested = Array.isArray(pedido.jogadores_sugeridos) ? [...pedido.jogadores_sugeridos] : []
  const dataLimite = pedido.data_limite ? pedido.data_limite.split('T')[0] : ''
  const isAdmin = state.role === 'admin' || state.role === 'moderator'

  const panel = document.getElementById('side-panel')
  const panelContent = document.getElementById('panel-content')
  if (!panel || !panelContent) return

  panelContent.innerHTML = `
    <div class="panel-header">
      <div class="panel-header-left">
        ${pedido.logo_url
          ? `<img src="${pedido.logo_url}" style="width:48px;height:48px;object-fit:contain;border-radius:10px;margin-right:14px;flex-shrink:0;" />`
          : `<div style="width:48px;height:48px;border-radius:10px;background:#dde1e7;margin-right:14px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#666;">${(pedido.clube||'?').substring(0,2).toUpperCase()}</div>`
        }
        <div style="min-width:0;">
          <div class="panel-name">${pedido.clube || 'Clube'}</div>
          <div class="panel-sub">${pedido.pais || '\u2014'}</div>
        </div>
      </div>
      <div style="display:flex;gap:8px;flex-shrink:0;">
        ${isAdmin ? `<button class="btn-panel-edit" id="ped-edit-btn">Editar</button>` : ''}
        <button class="btn-icon" id="panel-close-btn">${icon('close')}</button>
      </div>
    </div>

    <div class="panel-body">
      <div class="panel-section">
        <div class="panel-section-title">Pedido</div>
        <div class="info-grid">
          <div class="info-row"><span class="info-label">Posi\u00e7\u00e3o</span><span class="info-val">${pedido.posicao ? `<span class="pos-badge-panel">${pedido.posicao}</span>` : '\u2014'}</span></div>
        </div>
      </div>
      <div class="panel-section">
        <div class="panel-section-title">Modelo Financeiro</div>
        <div class="info-grid">
          <div class="info-row"><span class="info-label">Valor Transf.</span><span class="info-val">${pedido.valor_transferencia || '\u2014'}</span></div>
          <div class="info-row"><span class="info-label">Sal\u00e1rio</span><span class="info-val">${pedido.salario || '\u2014'}</span></div>
          <div class="info-row"><span class="info-label">Comiss\u00f5es</span><span class="info-val">${pedido.comissoes || '\u2014'}</span></div>
          <div class="info-row"><span class="info-label">Budget Total</span><span class="info-val">${pedido.budget_total || '\u2014'}</span></div>
        </div>
      </div>
      <div class="panel-section">
        <div class="panel-section-title">Outros Detalhes</div>
        <div class="info-grid">
          <div class="info-row"><span class="info-label">Introduzido por</span><span class="info-val">${pedido.introduzido_por || '\u2014'}</span></div>
          <div class="info-row"><span class="info-label">Data limite</span><span class="info-val">${dataLimite || '\u2014'}</span></div>
        </div>
      </div>
      <div class="panel-section">
        <div class="panel-section-title">Sugerir Jogador</div>
        <div style="position:relative;margin-bottom:12px;">
          <input class="form-input" id="ped-search-player" placeholder="Sugerir jogador..." autocomplete="off" style="width:100%;box-sizing:border-box;" />
          <div id="ped-suggestions" style="display:none;position:absolute;top:100%;left:0;right:0;background:var(--surface);border:1px solid var(--border);border-radius:8px;box-shadow:0 4px 16px rgba(0,0,0,0.12);z-index:200;max-height:200px;overflow-y:auto;"></div>
        </div>
        <div id="ped-jogadores-lista" style="display:flex;flex-wrap:wrap;gap:6px;min-height:24px;"></div>
      </div>
      ${isAdmin ? `
      <div style="padding:0 0 8px;">
        <button id="ped-delete" style="width:100%;padding:14px;border-radius:10px;border:none;background:#fff0f0;color:#dc2626;cursor:pointer;font-size:14px;font-weight:600;font-family:'DM Sans',sans-serif;">Eliminar pedido</button>
      </div>` : ''}
    </div>
  `

  panel.classList.add('open')
  document.getElementById('overlay').classList.add('show')
  document.getElementById('panel-close-btn').addEventListener('click', closePanel)

  // Sugerir jogador
  function updateJogadoresLista() {
    const lista = document.getElementById('ped-jogadores-lista')
    if (!lista) return
    if (!currentSuggested.length) {
      lista.innerHTML = '<span style="font-size:13px;color:var(--text-2);">Nenhum jogador sugerido ainda</span>'
      return
    }
    lista.innerHTML = currentSuggested.map(j => `
      <div style="display:flex;align-items:center;justify-content:space-between;background:#eff4ff;padding:8px 12px;border-radius:10px;margin-bottom:6px;">
        <div>
          <div style="font-size:13px;font-weight:600;color:#0061ff;">${j.nome}</div>
          <div style="font-size:11px;color:var(--text-2);margin-top:2px;">por ${j.sugerido_por || '\u2014'} ${j.sugerido_em ? '- ' + new Date(j.sugerido_em).toLocaleDateString('pt-PT') : ''}</div>
        </div>
        <button data-id="${j.id}" style="background:none;border:none;cursor:pointer;color:#0061ff;font-size:18px;line-height:1;padding:0 4px;" class="remove-jogador">\u00d7</button>
      </div>
    `).join('')
    lista.querySelectorAll('.remove-jogador').forEach(btn => {
      btn.addEventListener('click', async () => {
        currentSuggested = currentSuggested.filter(j => String(j.id) !== String(btn.dataset.id))
        await supabase.from('club_requests').update({ jogadores_sugeridos: currentSuggested }).eq('id', pedido.id)
        updateJogadoresLista()
      })
    })
  }
  updateJogadoresLista()

  const searchInput = document.getElementById('ped-search-player')
  const suggestions = document.getElementById('ped-suggestions')
  searchInput.addEventListener('input', () => {
    const q = searchInput.value.toLowerCase()
    if (!q) { suggestions.style.display = 'none'; return }
    const matches = allPlayers.filter(p => p.nome && p.nome.toLowerCase().includes(q) && !currentSuggested.find(s => String(s.id) === String(p.id))).slice(0, 8)
    if (!matches.length) { suggestions.style.display = 'none'; return }
    suggestions.style.display = 'block'
    suggestions.innerHTML = matches.map(p => {
      const init = initials(p.nome)
      const avatarHtml = p.foto
        ? `<img src="${p.foto}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;flex-shrink:0;" onerror="this.outerHTML='<div style=\\'width:32px;height:32px;border-radius:50%;background:var(--accent-light);display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:var(--accent);flex-shrink:0;\\'>${init}</div>'" />`
        : `<div style="width:32px;height:32px;border-radius:50%;background:var(--accent-light);display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:var(--accent);flex-shrink:0;">${init}</div>`
      return `
        <div class="suggestion-item" data-id="${p.id}" data-nome="${p.nome}" style="padding:8px 14px;cursor:pointer;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px;">
          ${avatarHtml}
          <div style="flex:1;min-width:0;">
            <div style="font-size:13px;font-weight:600;color:var(--text);">${p.nome}</div>
            <div style="font-size:12px;color:var(--text-2);">${p.clube || ''} \u00b7 ${p.posicao || ''}</div>
          </div>
        </div>
      `
    }).join('')
    suggestions.querySelectorAll('.suggestion-item').forEach(item => {
      item.addEventListener('mouseover', () => item.style.background = 'var(--bg)')
      item.addEventListener('mouseout', () => item.style.background = '')
      item.addEventListener('click', async () => {
        currentSuggested.push({ 
          id: item.dataset.id, 
          nome: item.dataset.nome,
          sugerido_por: state.userName || state.user?.email || 'desconhecido',
          sugerido_em: new Date().toISOString()
        })
        await supabase.from('club_requests').update({ jogadores_sugeridos: currentSuggested }).eq('id', pedido.id)
        searchInput.value = ''; suggestions.style.display = 'none'
        updateJogadoresLista()
        showToast('Jogador sugerido!', 'success')
      })
    })
  })
  document.addEventListener('click', function hideSug(e) {
    if (!suggestions.contains(e.target) && e.target !== searchInput) { suggestions.style.display = 'none'; document.removeEventListener('click', hideSug) }
  })

  if (isAdmin) {
    // Editar button opens form-panel (same as players)
    document.getElementById('ped-edit-btn').addEventListener('click', () => openPedidoForm(pedido))

    document.getElementById('ped-delete').addEventListener('click', async () => {
      if (!confirm('Eliminar este pedido?')) return
      await supabase.from('club_requests').delete().eq('id', pedido.id)
      showToast('Pedido eliminado.', 'success')
      closeAll()
      loadPedidos()
    })
  }
}

function openPedidoForm(pedido) {
  const isEdit = !!pedido
  const p = pedido || {}
  const dataLimite = p.data_limite ? p.data_limite.split('T')[0] : ''
  const formPanel = document.getElementById('form-panel')
  const formContent = document.getElementById('form-content')
  if (!formPanel || !formContent) return

  // Always replace the node to destroy all previous listeners
  const newContent = formContent.cloneNode(false)
  formContent.parentNode.replaceChild(newContent, formContent)

  newContent.innerHTML = `
    <div class="form-header">
      <div class="form-title">${isEdit ? 'Editar Pedido' : 'Novo Pedido'}</div>
      <button class="btn-icon" id="pf-close">${icon('close')}</button>
    </div>
    <div class="form-body">
      <div class="form-group">
        <label class="form-label">Clube</label>
        <input class="form-input" id="pf-form-clube" value="${p.clube || ''}" />
      </div>
      <div class="form-group">
        <label class="form-label">Pa\u00eds</label>
        <input class="form-input" id="pf-form-pais" value="${p.pais || ''}" />
      </div>
      <div class="form-group">
        <label class="form-label">Posi\u00e7\u00e3o</label>
        <select class="form-select" id="pf-form-posicao">
          <option value="">\u2014</option>
          ${POSICOES.map(pos => `<option value="${pos}" ${p.posicao===pos?'selected':''}>${pos}</option>`).join('')}
        </select>
      </div>
      <div class="form-group">
        <label class="form-label">Valor Transfer\u00eancia</label>
        <input class="form-input" id="pf-form-valor" value="${p.valor_transferencia || ''}" placeholder="Ex: \u20ac2M" />
      </div>
      <div class="form-group">
        <label class="form-label">Sal\u00e1rio</label>
        <input class="form-input" id="pf-form-salario" value="${p.salario || ''}" placeholder="Ex: \u20ac15k/m\u00eas" />
      </div>
      <div class="form-group">
        <label class="form-label">Comiss\u00f5es</label>
        <input class="form-input" id="pf-form-comissoes" value="${p.comissoes || ''}" placeholder="Ex: 5%" />
      </div>
      <div class="form-group">
        <label class="form-label">Budget Total</label>
        <input class="form-input" id="pf-form-budget" value="${p.budget_total || ''}" placeholder="Ex: \u20ac5M" />
      </div>
      <div class="form-group">
        <label class="form-label">Introduzido por</label>
        <input class="form-input" id="pf-form-intro" value="${p.introduzido_por || ''}" />
      </div>
      <div class="form-group">
        <label class="form-label">Data limite</label>
        <input class="form-input" type="date" id="pf-form-data" value="${dataLimite}" />
      </div>
      <div class="form-group">
        <label class="form-label">Logo do Clube</label>
        <div style="display:flex;flex-direction:column;gap:8px;">
          ${p.logo_url
            ? `<img id="pf-logo-preview" src="${p.logo_url}" style="width:64px;height:64px;border-radius:10px;object-fit:contain;background:#f0f0f0;" />`
            : `<div id="pf-logo-preview" style="width:64px;height:64px;border-radius:10px;background:var(--accent-light);display:flex;align-items:center;justify-content:center;font-size:11px;color:var(--text-2);">Sem logo</div>`
          }
          <input class="form-input" id="pf-form-logo-url" type="url" value="${p.logo_url && !p.logo_url.startsWith('data:') ? p.logo_url : ''}" placeholder="URL do logo (https://...)" />
          <label style="display:flex;align-items:center;gap:8px;padding:9px 12px;border:1px dashed var(--border-2);border-radius:var(--radius-sm);cursor:pointer;font-size:13px;color:var(--text-2);">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>
            Escolher ficheiro local
            <input type="file" id="pf-form-logo-file" accept="image/*" style="display:none;" />
          </label>
        </div>
      </div>
    </div>
    <div class="form-footer">
      <button class="btn-cancel" id="pf-cancel">Cancelar</button>
      <button class="btn-save" id="pf-form-save">${isEdit ? 'Guardar' : 'Criar pedido'}</button>
    </div>
  `

  document.getElementById('overlay').classList.add('show')
  formPanel.classList.add('open')

  // Close handlers
  document.getElementById('pf-close').addEventListener('click', closeAll)
  document.getElementById('pf-cancel').addEventListener('click', closeAll)

  // Logo file preview
  document.getElementById('pf-form-logo-file').addEventListener('change', e => {
    const file = e.target.files[0]
    if (!file) return
    const reader = new FileReader()
    reader.onload = ev => {
      const preview = document.getElementById('pf-logo-preview')
      if (preview) {
        const img = document.createElement('img')
        img.id = 'pf-logo-preview'
        img.src = ev.target.result
        img.style.cssText = 'width:64px;height:64px;border-radius:10px;object-fit:contain;background:#f0f0f0;'
        preview.replaceWith(img)
      }
      document.getElementById('pf-form-logo-url').value = ''
    }
    reader.readAsDataURL(file)
  })

  // SAVE â€” single listener, disabled guard
  document.getElementById('pf-form-save').addEventListener('click', async () => {
    const btn = document.getElementById('pf-form-save')
    if (btn.disabled) return
    btn.disabled = true
    btn.textContent = 'A guardar...'

    // Get logo
    let logoUrl = p.logo_url || null
    const fileInput = document.getElementById('pf-form-logo-file')
    const urlInput = document.getElementById('pf-form-logo-url').value.trim()
    if (fileInput && fileInput.files && fileInput.files[0]) {
      logoUrl = await new Promise(resolve => {
        const reader = new FileReader()
        reader.onload = e => resolve(e.target.result)
        reader.readAsDataURL(fileInput.files[0])
      })
    } else if (urlInput) {
      logoUrl = urlInput
    }

    const raw = {
      clube:               document.getElementById('pf-form-clube').value.trim()     || null,
      pais:                document.getElementById('pf-form-pais').value.trim()      || null,
      posicao:             document.getElementById('pf-form-posicao').value          || null,
      valor_transferencia: document.getElementById('pf-form-valor').value.trim()    || null,
      salario:             document.getElementById('pf-form-salario').value.trim()   || null,
      comissoes:           document.getElementById('pf-form-comissoes').value.trim() || null,
      budget_total:        document.getElementById('pf-form-budget').value.trim()    || null,
      introduzido_por:     document.getElementById('pf-form-intro').value.trim()     || null,
      data_limite:         document.getElementById('pf-form-data').value             || null,
      logo_url:            logoUrl,
    }
    const cleanData = Object.fromEntries(Object.entries(raw).filter(([_, v]) => v !== null))

    let error
    if (isEdit) {
      const res = await supabase.from('club_requests').update(cleanData).eq('id', p.id)
      error = res.error
    } else {
      const res = await supabase.from('club_requests').insert(cleanData)
      error = res.error
    }

    if (error) {
      showToast('Erro: ' + error.message, 'error')
      btn.disabled = false
      btn.textContent = isEdit ? 'Guardar' : 'Criar pedido'
      return
    }

    showToast(isEdit ? 'Pedido guardado!' : 'Pedido criado!', 'success')
    document.getElementById('form-panel').classList.remove('open')
    document.getElementById('overlay').classList.remove('show')
    await loadPedidos()
  })
}




async function loadPlayers() {
  if (state.activeDb === 'pedidos') { loadPedidos(); return }
  // Return cached data instantly
  if (state.dbCache[state.activeDb]) {
    state.players = state.dbCache[state.activeDb]
    state.loading = false
    updateList()
    return
  }
  const db = DATABASES.find(d => d.id === state.activeDb)
  let query
  if (db?.isGeral) {
    // Combine all tables
    const [r1, r2, r3] = await Promise.all([
      supabase.from('players').select('*'),
      supabase.from('players_mercado').select('*'),
      supabase.from('players_portugal').select('*'),
    ])
    if (r1.error || r2.error || r3.error) { showToast('Erro ao carregar dados.', 'error'); return }
    const all = [
      ...(r1.data || []).map(p => ({...p, _source: 'Mercado', _sourceTable: 'players_mercado'})),
      ...(r2.data || []).map(p => ({...p, _source: 'CBF Sele\u00e7\u00f5es', _sourceTable: 'players'})),
      ...(r3.data || []).map(p => ({...p, _source: 'FPF Sele\u00e7\u00f5es', _sourceTable: 'players_portugal'})),
    ].sort((a,b) => (a.nome||'').localeCompare(b.nome||''))
    state.players = all.map(p => ({ ...p, ano: p.ano != null ? String(p.ano) : '' }))
    state.dbCache[state.activeDb] = state.players
    state.loading = false
    updateList()
    return
  }
  const table = db?.table || 'players'
  const { data, error } = await supabase.from(table).select('*').order('nome')
  if (error) { showToast('Erro ao carregar dados.', 'error'); return }
  const activeDb = DATABASES.find(d => d.id === state.activeDb)
  state.players = (data || []).map(p => ({ ...p, ano: p.ano != null ? String(p.ano) : '', _sourceTable: activeDb?.table || 'players' }))
  state.dbCache[state.activeDb] = state.players
  state.loading = false
  updateList()
  preloadAll()
  // Subscribe to realtime updates
  if (!state.realtimeChannel) {
    state.realtimeChannel = supabase
      .channel('players-changes')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'players' }, (payload) => {
        const novo = payload.new
        if (novo && novo.nome) {
          sendLocalNotification('Novo jogador adicionado!', `${novo.nome} foi adicionado \u00e0 base de dados.`)
          loadPlayers()
        }
      })
      .subscribe()
  }
}

async function fetchRole() {
  const { data } = await supabase.from('user_roles').select('role,nome').eq('id', state.user.id).single()
  state.role = data?.role || 'viewer'
  state.userName = data?.nome || state.user.email
}

async function requestNotificationPermission() {
  if (!('Notification' in window)) return
  if (Notification.permission === 'default') {
    await Notification.requestPermission()
  }
}

function sendLocalNotification(title, body) {
  if (!('Notification' in window) || Notification.permission !== 'granted') return
  try {
    new Notification(title, {
      body,
      icon: '/icon-192.png',
      badge: '/icon-192.png',
    })
  } catch(e) {
    // Use service worker notification as fallback
    if (navigator.serviceWorker && navigator.serviceWorker.controller) {
      navigator.serviceWorker.ready.then(reg => {
        reg.showNotification(title, { body, icon: '/icon-192.png' })
      })
    }
  }
}

function resetState() {
  state.search = ''
  state.filterPos = ''
  state.filterNivel = ''
  state.filterAno = ''
  state.sortCol = 'nome'
  state.sortDir = 1
  state.selectedPlayer = null
  state.editingPlayer = null
  state.players = []
  state.filtered = []
  state.loading = true
  state.pedidoSearch = ''
  state.pedidoFilterPos = ''
  state.pedidoFilterClube = ''
  state.pedidoFilterPais = ''
  state.userName = ''
}

// Intercept Android back button
function pushPanelState() {
  history.pushState({ panel: true }, '', location.pathname)
}

window.addEventListener('popstate', (e) => {
  const panel = document.getElementById('side-panel')
  const form = document.getElementById('form-panel')
  const overlay = document.getElementById('overlay')
  const anyOpen = (panel && panel.classList.contains('open')) || (form && form.classList.contains('open'))
  if (anyOpen) {
    // Close whatever is open and push state again to stay in app
    if (form && form.classList.contains('open')) {
      form.classList.remove('open')
    }
    if (panel && panel.classList.contains('open')) {
      panel.classList.remove('open')
    }
    if (overlay) overlay.classList.remove('open')
    // Push state again so next back still stays in app
    history.pushState({ panel: false }, '', location.pathname)
  }
})


async function offerBiometricSetup(email) {
  if (!localStorage.getItem(WA_KEY) && await isBiometricAvailable()) {
    // Show register button in topbar
    const topbarRight = document.querySelector('.topbar-right')
    if (!topbarRight) return
    const existing = document.getElementById('btn-setup-bio')
    if (existing) return
    const btn = document.createElement('button')
    btn.id = 'btn-setup-bio'
    btn.className = 'btn-add'
    btn.style.background = 'var(--green)'
    btn.style.fontSize = '12px'
    btn.innerHTML = `<svg viewBox="0 0 32 32" fill="none" width="18" height="18"><path d="M16 4C9.373 4 4 9.373 4 16" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><path d="M28 16c0 6.627-5.373 12-12 12" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><path d="M16 10a6 6 0 0 1 6 6c0 2-.4 3.9-1.1 5.6" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><path d="M10 16a6 6 0 0 1 6-6" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><path d="M16 16v8" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><path d="M13 19c0 2.5.8 4.8 2.1 6.7" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><path d="M19 19c0 1.4-.2 2.7-.7 3.9" stroke="#0066ff" stroke-width="2" stroke-linecap="round"/><circle cx="16" cy="16" r="2" fill="#0066ff"/></svg><span>Ativar digital</span>`
    btn.addEventListener('click', () => window.setupBiometric(email))
    topbarRight.insertBefore(btn, topbarRight.firstChild)
  }
}

window.setupBiometric = async function(email) {
  const toast = document.getElementById('toast')
  toast.classList.remove('show')
  const ok = await registerBiometric(email)
  setTimeout(() => {
    showToast(ok ? 'Impress\u00e3o digital ativada! \u2713' : 'N\u00e3o foi poss\u00edvel ativar.', ok ? 'success' : 'error')
  }, 300)
}

async function init() {
  const { data: { session } } = await supabase.auth.getSession()
  state.user = session?.user || null
  if (!state.user) {
    // Store shared player id to open after login
    const hash = location.hash
    if (hash && hash.startsWith('#player=')) {
      localStorage.setItem('open_player', hash.replace('#player=', ''))
    }
    renderAuth(); return
  }
  await fetchRole()
  if (location.pathname === '/pedidos') {
    renderPedidosPage()
  } else {
    renderApp()
    preloadAll()
    await loadPlayers()
  }
  // Open shared player from URL hash
  function checkAndOpenSharedPlayer() {
    const hash = location.hash
    if (hash && hash.startsWith('#player=')) {
      const playerId = hash.replace('#player=', '')
      const player = state.players.find(p => p.id === playerId)
      if (player) {
        // Clear hash first
        history.replaceState(null, '', location.pathname)
        // Push state so back button closes panel instead of exiting app
        history.pushState({ panel: true }, '', location.pathname)
        openPanel(player)
      }
    }
  }
  checkAndOpenSharedPlayer()
  
  // Push initial state AFTER reading hash, so back button works
  if (!location.hash) {
    history.replaceState({ panel: false }, '', location.pathname)
  }

  // Also store for after login if not yet authenticated
  const openPlayerId = localStorage.getItem('open_player')
  if (openPlayerId) {
    localStorage.removeItem('open_player')
    setTimeout(() => {
      const player = state.players.find(p => p.id === openPlayerId)
      if (player) openPanel(player)
    }, 500)
  }
  supabase.auth.onAuthStateChange(async (event, session) => {
    state.user = session?.user || null
    if (!state.user) { resetState(); renderAuth() }
    else if (event === 'SIGNED_IN') {
      await fetchRole()
      renderApp()
      loadPlayers()
      if (session?.user?.email) offerBiometricSetup(session.user.email)
      requestNotificationPermission()
    }
  })
}

init()
